package ua.university.sms.controller;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import ua.university.sms.model.dto.EnrollmentDtos.*;import ua.university.sms.service.EnrollmentService;import java.util.*;
@RestController @RequestMapping("/api/enrollments") public class EnrollmentController{private final EnrollmentService s;public EnrollmentController(EnrollmentService s){this.s=s;}@PostMapping public ResponseEntity<Response> create(@Valid @RequestBody Request r){return ResponseEntity.status(201).body(s.create(r));}@GetMapping("/{id}") public Response get(@PathVariable Long id){return s.get(id);}@GetMapping public List<Response> list(){return s.list();}@PutMapping("/{id}") public Response update(@PathVariable Long id,@Valid @RequestBody Request r){return s.update(id,r);}@PatchMapping("/{id}/payment") public Response payment(@PathVariable Long id,@RequestBody PaymentRequest r){return s.setPaid(id,r);}@PatchMapping("/{id}/grade") public Response grade(@PathVariable Long id,@Valid @RequestBody GradeRequest r){return s.setGrade(id,r);}@GetMapping("/average/course/{courseId}") public Double avgCourse(@PathVariable Long courseId){return s.averageByCourse(courseId);}@GetMapping("/average/semester/{semester}") public Double avgSemester(@PathVariable String semester){return s.averageBySemester(semester);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable Long id){s.delete(id);}}
